output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "In the 'Input CT Volume' dropdown, choose the Pelvic Volume.",
      "detailed": "This step identifies the CT scan of the pelvis that will be used for all subsequent segmentation and planning. The pelvic volume must contain the full bony anatomy including fracture fragments. Select the correct volume from the dropdown list to proceed."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button.",
      "detailed": "This automatically segments the bony pelvis from the CT volume, creating a 3D model that separates the pelvic bone from surrounding soft tissue. The resulting segmentation is the foundation for identifying fracture fragments in the next step."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fractures",
      "simple": "Click the 'Run Step 2: Segment Fractures' button.",
      "detailed": "This step analyses the pelvic segmentation to automatically identify and separate individual fracture fragments. Each fragment is assigned a distinct label, which is critical for planning reduction and screw placement later."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Fragments from Planning",
      "simple": "Untick any fracture fragments you wish to exclude from the surgical plan.",
      "detailed": "You may choose to exclude certain fragments that are not relevant for the planned fixation, such as small avulsion fragments or fragments that will not be instrumented. Uncheck the corresponding boxes to remove them from the planning algorithm."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the 'Run Step 3: Generate Template' button.",
      "detailed": "This creates a template for reducing the fracture fragments back to their anatomical position. The template is used in the next step to automatically align the fragments for optimal reduction before screw planning."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fragments",
      "simple": "Click the 'Run Step 4: Register Reduce' button.",
      "detailed": "This step automatically aligns the fracture fragments to the reduction template, bringing them into their intended postoperative position. The result is a reduced pelvis segmentation that serves as the basis for screw trajectory planning."
    },
    {
      "step_id": "cb_step_7",
      "title": "Manual Fragment Adjustment?",
      "simple": "Check 'Manually adjust a fragment' if you need to fine-tune the position of any fragment, or skip to step 10 if the automatic reduction is satisfactory.",
      "detailed": "The automatic reduction may not be perfect in complex fractures. If a fragment appears misaligned (e.g., gap, rotation, or displacement), checking this box will allow you to manually correct its position before proceeding to screw planning."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment to Adjust",
      "simple": "From the 'Fragment' dropdown, choose the fragment that needs manual adjustment.",
      "detailed": "Pick the fragment that appears incorrectly positioned. Selecting it here will activate the controls to move and rotate it in the 3D view."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position and Rotation",
      "simple": "Use the 3D view to move and rotate the selected fragment until it fits correctly.",
      "detailed": "You can translate and rotate the fragment in the 3D viewer to achieve anatomical alignment. This manual refinement is essential for complex fractures where the automatic reduction requires fine-tuning. The adjustment directly affects the final screw planning."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Fragment Adjustments",
      "simple": "Click the 'Apply adjustments' button to finalize the manual fragment position.",
      "detailed": "This saves the manual changes you made and updates the reduction model with the corrected fragment positions. Confirm that the fragment is in a satisfactory position before proceeding."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Trajectories",
      "simple": "Click the 'Run Step 5: Plan Screws' button.",
      "detailed": "This automatically generates planned screw trajectories for the reduced pelvis. The algorithm considers bone anatomy, fracture pattern, and safe corridors to propose optimal screw positions and orientations for fixation."
    },
    {
      "step_id": "cb_step_12",
      "title": "Edit Screw Trajectories?",
      "simple": "Check 'Edit Screw trajectories' if you need to modify the planned screw positions, or stop here if satisfied.",
      "detailed": "The automatically planned screws may not match your surgical preference perfectly. Checking this box allows you to manually adjust screw trajectories—for example, to avoid a critical structure or improve purchase. If the plan is acceptable, no further action is needed."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "In the 3D view, move and rotate the screw trajectories to your preferred positions.",
      "detailed": "You can fine-tune each screw's entry point, direction, and depth using the 3D view. This is important for avoiding neurovascular bundles, articular surfaces, or other critical anatomy. Ensure each screw has adequate bone purchase and safe clearance."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws from Edited Trajectories",
      "simple": "Click the 'Regenerate screw from edited lines' button.",
      "detailed": "After manual adjustments, this step recalculates the final screw models based on your edited trajectories. The regenerated screws reflect your changes and will be used for the final plan."
    },
    {
      "step_id": "cb_step_15",
      "title": "Finalize Screw Plan",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to commit the final screw plan.",
      "detailed": "This exits the edit mode and finalizes the screw trajectories. The plan is now complete and ready for review or export."
    }
  ]
}
